            return null;
        }
        if (byte >= 0x40 and byte <= 0x7e) return self.dispatchCsi(byte);
        self.state = .csi_ignore;
        return null;
    }

    fn handleCsiIntermediate(self: *Parser, byte: u8) ?InputEvent {
