test "parse CSI sgr" {
    var p = Parser.init();
    _ = p.feed(0x1b);
    _ = p.feed('[');
    _ = p.feed('3');
    _ = p.feed('1');
    const event = p.feed('m').?;
    switch (event) {
        .csi => |csi| {
